<script setup lang="ts">
import { computed, onMounted, reactive, ref } from 'vue'
import type { AnalyticsDashboard } from '../analytics'
import { ApiError, apiRequest, authState } from '../auth'
import type { Department } from '../organization'
import type { Employee, EmployeePage } from '../employee'
import type { Product, ProductPage } from '../product'
import AppShell from '../components/AppShell.vue'

const dashboard = ref<AnalyticsDashboard | null>(null); const departments = ref<Department[]>([]); const employees = ref<Employee[]>([]); const products = ref<Product[]>([])
const loading = ref(true); const errorMessage = ref('')
const canAll = computed(() => authState.user?.permissions.includes('analytics.all') ?? false)
const canExport = computed(() => authState.user?.permissions.includes('analytics.export') ?? false)
const apiBase = import.meta.env.VITE_API_BASE_URL ?? 'http://localhost:8000/api/v1'
const now = new Date(); const start = new Date(now); start.setDate(start.getDate() - 29)
const dateText = (value: Date) => value.toISOString().slice(0, 10)
const filters = reactive({ date_from: dateText(start), date_to: dateText(now), department_id: '', employee_id: '', product_id: '', channel: '', ranking_dimension: 'employee' })
const percent = (value: number | null) => value == null ? '—' : `${(value * 100).toFixed(1)}%`
const maxTrend = computed(() => Math.max(1, ...(dashboard.value?.trend.map(item => Math.max(item.views, item.leads, item.conversions)) ?? [1])))
async function loadOptions() { if (!canAll.value) return; const [departmentValues, employeeValues, productValues] = await Promise.all([apiRequest<Department[]>('/tenant/departments'), apiRequest<EmployeePage>('/tenant/employees?limit=100'), apiRequest<ProductPage>('/tenant/products?limit=100')]); departments.value = departmentValues; employees.value = employeeValues.items; products.value = productValues.items }
async function load() { loading.value = true; errorMessage.value = ''; try { const params = new URLSearchParams(); Object.entries(filters).forEach(([key, value]) => { if (value) params.set(key, value) }); dashboard.value = await apiRequest(`/tenant/analytics/dashboard?${params}`) } catch (error) { errorMessage.value = error instanceof ApiError ? error.message : '经营数据加载失败' } finally { loading.value = false } }
async function exportCsv() { const params = new URLSearchParams({ date_from: filters.date_from, date_to: filters.date_to }); const response = await fetch(`${apiBase}/tenant/analytics/export?${params}`, { headers: { Authorization: `Bearer ${authState.accessToken}` } }); if (!response.ok) { errorMessage.value = '报表导出失败'; return } const url = URL.createObjectURL(await response.blob()); const anchor = document.createElement('a'); anchor.href = url; anchor.download = `digitalcard-analytics-${filters.date_from}-${filters.date_to}.csv`; anchor.click(); URL.revokeObjectURL(url) }
onMounted(async () => { try { await loadOptions() } catch { /* Options do not block personal analytics. */ } await load() })
</script>

<template><AppShell><header class="page-header compact"><div><p class="eyebrow">BUSINESS ANALYTICS</p><h1>经营数据分析</h1><p>了解访问来源、内容效果及从名片到客户的转化。</p></div><div class="header-actions"><button v-if="canExport" class="secondary-button" @click="exportCsv">导出 CSV</button><button class="primary-button" @click="load">刷新数据</button></div></header><div v-if="errorMessage" class="notice error">{{ errorMessage }}</div><section class="panel analytics-filters"><label><span>开始日期</span><input v-model="filters.date_from" type="date" /></label><label><span>结束日期</span><input v-model="filters.date_to" type="date" /></label><label v-if="canAll"><span>部门</span><select v-model="filters.department_id"><option value="">全部部门</option><option v-for="item in departments" :key="item.id" :value="item.id">{{ item.name }}</option></select></label><label v-if="canAll"><span>员工</span><select v-model="filters.employee_id"><option value="">全部员工</option><option v-for="item in employees" :key="item.id" :value="item.id">{{ item.name }}</option></select></label><label v-if="canAll"><span>产品</span><select v-model="filters.product_id"><option value="">全部产品</option><option v-for="item in products" :key="item.id" :value="item.id">{{ item.name }}</option></select></label><label><span>渠道</span><input v-model.trim="filters.channel" placeholder="如 wechat" /></label><label><span>排行维度</span><select v-model="filters.ranking_dimension"><option value="department">部门</option><option value="employee">员工</option><option value="card">名片</option><option value="product">产品</option><option value="channel">渠道</option></select></label></section><div v-if="loading" class="panel empty-state">正在汇总经营数据…</div><template v-else-if="dashboard"><section class="metric-grid analytics-metrics"><article><span>有效访问</span><strong>{{ dashboard.metrics.views }}</strong><p>{{ dashboard.metrics.unique_visitors }} 位独立访客</p></article><article><span>分享 / 点击</span><strong>{{ dashboard.metrics.shares }} / {{ dashboard.metrics.clicks }}</strong><p>内容互动效果</p></article><article><span>有效留资</span><strong>{{ dashboard.metrics.leads }}</strong><p>访问转留资 {{ percent(dashboard.metrics.view_to_lead_rate) }}</p></article><article><span>客户转化</span><strong>{{ dashboard.metrics.conversions }}</strong><p>留资转客户 {{ percent(dashboard.metrics.lead_to_customer_rate) }}</p></article></section><section class="analytics-layout"><article class="panel"><div class="section-heading"><div><p class="eyebrow">TREND</p><h2>每日趋势</h2></div><small>绿色访问 · 金色留资 · 深色转化</small></div><div class="trend-chart"><div v-for="point in dashboard.trend" :key="point.date" class="trend-column" :title="`${point.date} 访问 ${point.views} 留资 ${point.leads} 转化 ${point.conversions}`"><div><i class="views" :style="{ height: `${point.views / maxTrend * 100}%` }" /><i class="leads" :style="{ height: `${point.leads / maxTrend * 100}%` }" /><i class="conversions" :style="{ height: `${point.conversions / maxTrend * 100}%` }" /></div><small>{{ point.date.slice(5) }}</small></div></div></article><article class="panel"><p class="eyebrow">FUNNEL</p><h2>转化漏斗</h2><div class="conversion-funnel"><div v-for="(item, index) in dashboard.funnel" :key="item.code" :style="{ width: `${100 - index * 18}%` }"><b>{{ item.name }}</b><strong>{{ item.value }}</strong><small v-if="item.previous_rate != null">上一步转化 {{ percent(item.previous_rate) }}</small></div></div></article></section><section class="analytics-layout"><article class="panel table-panel"><p class="eyebrow">RANKING</p><h2>内容与渠道排行</h2><div v-if="!dashboard.ranking.length" class="empty-state">当前范围暂无排行数据</div><table v-else><thead><tr><th>维度</th><th>访问</th><th>留资</th><th>转化</th></tr></thead><tbody><tr v-for="item in dashboard.ranking" :key="item.dimension_id"><td>{{ item.dimension_name }}</td><td>{{ item.views }}</td><td>{{ item.leads }}</td><td>{{ item.conversions }}</td></tr></tbody></table></article><article class="panel"><p class="eyebrow">QUALITY</p><h2>数据质量</h2><p>已过滤机器人事件：<b>{{ dashboard.filtered_bot_events }}</b></p><p>已过滤内部访问：<b>{{ dashboard.filtered_internal_events }}</b></p><p>统计范围：{{ dashboard.scope === 'company' ? '全企业' : '本人数据' }}</p><p>最后更新时间：{{ dashboard.last_updated_at ? new Date(dashboard.last_updated_at).toLocaleString() : '暂无事件' }}</p><details><summary>查看指标口径</summary><article v-for="item in dashboard.definitions" :key="item.code" class="definition-item"><b>{{ item.name }}</b><p>{{ item.formula }}</p><small>{{ item.deduplication }}</small></article></details></article></section><section class="panel table-panel"><p class="eyebrow">TRACE SAMPLE</p><h2>事件抽样追溯</h2><div v-if="!dashboard.samples.length" class="empty-state">暂无可追溯事件</div><table v-else><thead><tr><th>时间</th><th>事件</th><th>渠道</th><th>员工</th><th>名片 / 产品</th><th>线索 / 客户</th></tr></thead><tbody><tr v-for="event in dashboard.samples" :key="event.id"><td>{{ new Date(event.occurred_at).toLocaleString() }}</td><td>{{ event.event_type }}</td><td>{{ event.channel }}</td><td>{{ event.employee_id || '—' }}</td><td>{{ event.card_id || '—' }}<small>{{ event.product_id || '' }}</small></td><td>{{ event.lead_id || '—' }}<small>{{ event.customer_id || '' }}</small></td></tr></tbody></table></section></template></AppShell></template>
